query:
{
  postgreSqlFlexibleServers(
    where: {
      NOT: {
        OR: [
          { engineVersion_MATCHES: "^11(\\.|$)" }
          { engineVersion_MATCHES: "^12(\\.|$)" }
          { engineVersion_MATCHES: "^13(\\.|$)" }
          { engineVersion_MATCHES: "^14(\\.|$)" }
          { engineVersion_MATCHES: "^15(\\.|$)" }
          { engineVersion_MATCHES: "^16(\\.|$)" }
          { engineVersion_MATCHES: "^17(\\.|$)" }
          { engineVersion_MATCHES: "^18(\\.|$)" }
        ]
      }
    }
  ) {
    ...AssetFragment
    engineVersion
  }
}
